import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    # Connect to the database
    conn = psycopg2.connect(host="localhost", dbname="mydatabase")
    cur = conn.cursor()

    # Build the SQL query based on the filter criteria
    sql = "SELECT * FROM users"
    params = []
    if username is not None:
        sql += " WHERE username = %s"
        params.append(username)
    if email is not None:
        sql += " AND email = %s"
        params.append(email)
    if role is not None:
        sql += " AND role IN (%s)"
        params.extend(["'admin'", "'user'", "'guest'"])
    if status is not None:
        sql += " AND status IN (%s)"
        params.extend(["'active'", "'suspended'"])

    # Execute the SQL query and return the results
    cur.execute(sql, params)
    rows = cur.fetchall()
    return [dict((cur.description[i][0], value) for i, value in enumerate(row)) for row in rows]